const data = $input.first().json;
const repos = data.repos || {};
const totalCommits = data.total_commits || 0;
const devlogContent = data.devlog_content || '';

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/New_York' });
const dateSlug = now.toISOString().split('T')[0];

// Build repo summaries
let repoSummaries = [];
for (const [repo, commits] of Object.entries(repos)) {
  const types = {};
  commits.forEach(c => {
    const match = c.message.match(/^(feat|fix|refactor|chore|docs|test|perf|style|ci):/i);
    const type = match ? match[1].toLowerCase() : 'other';
    types[type] = (types[type] || 0) + 1;
  });
  repoSummaries.push({ repo, count: commits.length, types, commits: commits.slice(0, 10) });
}

const prompt = `You are the lead developer writing the daily development blog post for the Parthenon platform (https://parthenon.acumenus.net). Parthenon is a unified OHDSI outcomes research platform for healthcare analytics.

Today is ${dateStr}. Write a developer blog post summarizing today's development progress across the Acumenus platform suite.

GIT ACTIVITY (${totalCommits} commits across ${repoSummaries.length} repos):
${repoSummaries.map(r => {
  const typeStr = Object.entries(r.types).map(([t,c]) => `${c} ${t}`).join(', ');
  return `\n**${r.repo}** (${r.count} commits: ${typeStr}):\n${r.commits.map(c => `- ${c.hash} ${c.message}`).join('\n')}`;
}).join('\n')}

RECENT DEVLOG NOTES:
${devlogContent.substring(0, 2000) || 'No recent devlog updates'}

Write a Docusaurus blog post in markdown with YAML frontmatter. Follow this exact format:

---
slug: dev-diary-${dateSlug}
title: "<descriptive title about today's work>"
authors: [mudoshi, claude]
tags: [<relevant tags from: development, ohdsi, analytics, frontend, backend, infrastructure, ai, database, testing, deployment, medicosts, medgnosis, aurora, mindlog, zephyrus>]
date: ${dateSlug}
---

<opening paragraph summarizing the day>

<!-- truncate -->

<rest of the post organized by theme/repo>

Guidelines:
- Focus on WHAT was built and WHY it matters, not just listing commits
- Group related changes thematically (e.g., "Analysis Visualization Overhaul", "Authentication System Updates")
- Include technical details that would be useful for future developers
- Mention specific files/components when relevant
- End with a "What's Next" section
- Keep it technical but readable
- 500-1000 words`;

return [{
  json: {
    prompt,
    dateSlug,
    dateStr,
    totalCommits,
    repoCount: repoSummaries.length,
    filename: `${dateSlug}-dev-diary.md`
  }
}];

const response = $input.first().json;
const promptData = $('Build Blog Prompt').first().json;

let markdown = '';
if (response.content && response.content[0]) {
  markdown = response.content[0].text;
}

// Clean up: ensure it starts with frontmatter
if (!markdown.startsWith('---')) {
  const fmIdx = markdown.indexOf('---');
  if (fmIdx >= 0) {
    markdown = markdown.substring(fmIdx);
  }
}

return [{
  json: {
    markdown,
    filename: promptData.filename,
    dateSlug: promptData.dateSlug
  }
}];
